{
    return (
        <div>
            <div classname="py-3 bg-warning">
                <div classname="container">
                    <h6>Collections / Category / Product</h6>
                </div>
            </div>

            <div className="py-3">
                <div className="container">
                    <div className="row">
                        <h4>Product Detail Page</h4>
                    </div>
                </div>
            </div>
        </div>
    )
} export default ProductDetails;
